// Get the input string
const input = $input.first().json.choices[0].message.content;

// Clean up the text by removing backslashes before 'n' and triple backticks
const cleanedString = input
    .replace(/^```[a-z]*\n?/, '') // Remove starting triple backticks with optional language
    .replace(/```$/, ''); // Remove ending triple backticks

// Return the cleaned text
return [{ cleanedHTML: cleanedString }];
